//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageelbimport("fmt""github.com/YakDriver/regexache")funcValidName(vinterface{},kstring)(ws[]string,errors[]error){value:=v.(string)iflen(value)==0{return//short-circuit}iflen(value)>32{errors=append(errors,fmt.Errorf("%qcannotbelongerthan32characters:%q",k,value))}if!regexache.MustCompile(`^[0-9A-Za-z-]+$`).MatchString(value){errors=append(errors,fmt.Errorf("onlyalphanumericcharactersandhyphensallowedin%q:%q",k,value))}ifregexache.MustCompile(`^-`).MatchString(value){errors=append(errors,fmt.Errorf("%qcannotbeginwithahyphen:%q",k,value))}ifregexache.MustCompile(`-$`).MatchString(value){errors=append(errors,fmt.Errorf("%qcannotendwithahyphen:%q",k,value))}return}funcvalidNamePrefix(vinterface{},kstring)(ws[]string,errors[]error){value:=v.(string)if!regexache.MustCompile(`^[0-9A-Za-z-]+$`).MatchString(value){errors=append(errors,fmt.Errorf("onlyalphanumericcharactersandhyphensallowedin%q:%q",k,value))}iflen(value)>6{errors=append(errors,fmt.Errorf("%qcannotbelongerthan6characters:%q",k,value))}ifregexache.MustCompile(`^-`).MatchString(value){errors=append(errors,fmt.Errorf("%qcannotbeginwithahyphen:%q",k,value))}return}